const items = [
  { url: "https://www.01net.com/rss/actualites/", source: "01net" },
  { url: "https://industrialcyber.co/feed/", source: "Industrial Cyber" },
  { url: "https://www.cert.ssi.gouv.fr/feed/", source: "CERT-FR" },
  { url: "https://securityaffairs.com/feed", source: "Security Affairs" },
  { url: "https://therecord.media/feed", source: "The Record" },
];

return items.map(item => ({ json: item }));

for (const item of $input.all()) {
  item.json.cleanedXml = item.json.data.replace(/&/g, '&amp;');
}
return $input.all();

const items = [];

for (const input of $input.all()) {
  const rss = input.json.rss;

  // Récupère la structure principale du flux (gère les variantes de nom "canal" ou "channel")
  const canal = rss && (rss.canal || rss.channel);
  if (!canal) continue; // Si le flux est vide ou invalide, passe au suivant

  // Récupère la liste des articles (gère toutes les variantes de balises possibles)
  const articles = canal.article || canal.item || canal.entry || [];

  // Récupère les données des articles
  for (const article of articles) {
    const cat = article.Catégorie || article.catégorie || article.Categories || article.categories || article.category || [];
    const titre = article.Titre || article.titre || article.title || '';



   // ------------------------------------------ HASH Unique


    const str = titre.toLowerCase().trim();
    let hash = 0;                                   // transformer le texte du titre en nombre unique
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // (32-bit)
    }

    const hashStr = Math.abs(hash).toString(16).padStart(8, '0');  // Transforme le nombre en une chaîne de 8 caractères hexadécimaux

 // ------------------------------------------ PUSH

    // Push les articles formalisé dans le tableau final en sortie
    items.push({ json: {
      hash: hashStr,
      titre,
      lien: article.Lien || article.lien || article.link,
      date: article['date de publication'] || article.pubDate, 
      auteur: Array.isArray(article['dc:creator']) ? article['dc:creator'][0] : article['dc:creator'],
      description: (article.Description || article.description || '').replace(/<[^>]*>/g, '').trim(),
      // Fusionne les catégories en une seule chaîne de texte séparée par des virgules si c'est une liste
      categories: Array.isArray(cat) ? cat.join(', ') : cat
    }});
  }
}

// 5. Return la liste finale des articles
return items;

// 1. Déduplication basée sur la mémoire SQL
const existingHashes = new Set(
  $('Execute a SQL query').all().map(i => i.json.hash)
);

// supprime les doublons existant et les rejette
const newItems = $('Code in JavaScript2').all().filter(item =>
  !existingHashes.has(item.json.hash)
);

// -- mot clé que l'article doit avoir
const CYBER_THREAT_PATTERNS = [
  /\bcyber/, /\bataque/, /\battack/, /\bbreach/, /\bzero[- ]day/, /\bransomware/, 
  /\bfaill/, /\bvulnerab/, /\bpirat/, /\bmalware/, /\bintrus/, /\bfaill/,
  /\bexfiltr/, /\bcomprom/, /\bapit\b/, /\bthreat/, /\bexploit/, /\bpoC\b/
];


const ASSET_AND_TECH_PATTERNS = [
  // --- Métiers SUEZ (Water / Waste Management) ---
  /\bwater/, /\beau\b/, /\bhydraul/, /\bwastewater/, /\bassainiss/, /\bsemma\b/,
  /\bwaste/, /\bdéchet/, /\brecycl/, /\border\b/, /\binciner/, /\bcompost/,

  // --- Énergie
  /\benerg/, /\bsmart[- ]meter/, /\blinky/, /\butilit/, /\bgrid/,

  // --- Informatique Industrielle (OT / ICS)
  /\bscada/, /\bplc\b/, /\bdcs\b/, /\bopc\b/, /\bindustrial/, /\bindustrie/,
  /\bautomati/, /\bics\b/, /\btelemetr/, /\binfrastructure[s]? critique[s]?/,

  // --- Constructeurs OT Critiques ---
  /\bschneider/, /\bsiemens/, /\brockwell/, /\babb\b/, /\bge\b/, /\bfoxboro/, /\becostruxure/,

  // --- Stack IT d'Entreprise sensible ---
  /\bazure/, /\bmicrosoft\b/, /\bzscaler/, /\bcrowdstrike/, /\bsplunk/, /\bsap\b/
];

return newItems.filter(item => {
  const text = (
    (item.json.titrePropre ?? item.json.titre ?? item.json.title ?? "") + " " +
    (item.json.DescriptionPropre ?? item.json.description ?? item.json.contentSnippet ?? item.json.content ?? "") + " " +
    (item.json.categories ?? "")
  ).toLowerCase();

  // au moins un mot clé présent 
  const hasThreat = CYBER_THREAT_PATTERNS.some(regex => regex.test(text)); // stock les mot clé dans hasThreat coté cyber
  const hasTarget = ASSET_AND_TECH_PATTERNS.some(regex => regex.test(text)); // stock les mot clé dans hasThreat coté techno - secteur

  // une menace ET que cela cible un actif d'intérêt pour (SUEZ)
  return hasThreat && hasTarget;
});

const activeItems = Array.isArray(items) ? items : [items];

for (let i = 0; i < activeItems.length; i++) {
  const d = activeItems[i].json;

  // Extraction des données de base
  const rawTitre = d.titre ?? d.titre_original ?? "";
  const rawResume = d.resume ?? "";
  const lien = d.lien ?? "#";
  const date = d.date ?? "";
  const criticite = Number.isInteger(d.criticite) ? d.criticite : parseInt(d.criticite, 10) || 0;
  const secteurCible = d.secteur_cible ?? "Inconnu";

  // 1. DÉTECTION DE LA LANGUE PAR SCORE
  const textToAnalyze = (rawTitre + " " + rawResume).toLowerCase();
  const frScore = (textToAnalyze.match(/\b(le|la|les|des|du|en|pour|dans|une|qui|est|sur|par|avec)\b/g) || []).length;
  const enScore = (textToAnalyze.match(/\b(the|and|of|with|to|for|is|at|on|by|from|warns|has)\b/g) || []).length;

  const isEn = enScore > frScore;
  const txtInconnu = isEn ? "Unknown" : "Inconnu";
  const titre = rawTitre || (isEn ? "No title" : "Sans titre");

  // 2. GESTION BILINGUE DU NIVEAU
  let rawNiveau = (d.niveau ?? "").toString().trim().toLowerCase();
  let niveau = isEn ? "Unknown" : "Inconnu";

  if (["critique", "critical"].includes(rawNiveau) || criticite >= 8) niveau = isEn ? "Critical" : "Critique";
  else if (["élevé", "eleve", "high"].includes(rawNiveau) || criticite >= 5) niveau = isEn ? "High" : "Élevé";
  else if (["moyen", "medium"].includes(rawNiveau) || criticite >= 3) niveau = isEn ? "Medium" : "Moyen";
  else if (["faible", "low"].includes(rawNiveau) || criticite > 0) niveau = isEn ? "Low" : "Faible";

  // 3. NETTOYAGE DES VALEURS PAR DÉFAUT
  const cleanVal = (val) => {
    if (!val) return txtInconnu;
    const v = val.toString().trim().toLowerCase();
    if (["inconnu", "unknown", "none", "n/a", "non spécifié", ""].includes(v)) return txtInconnu;
    return val;
  };

  const attaquants = cleanVal(d.attaquants);
  const victimes = cleanVal(d.victimes);
  const impact = cleanVal(d.impact);
  const recommandation = cleanVal(d.recommandation_suez);

  const techniques = Array.isArray(d.techniques) ? d.techniques : [];
  const outils = Array.isArray(d.outils_utilises) ? d.outils_utilises : [];
  const technologies = Array.isArray(d.technologies_concernees) ? d.technologies_concernees : [];

  if (i > 0) await new Promise(r => setTimeout(r, 3000));

  // 4. COULEURS THÈME ANSSI
  const niveauCfg = {
    "Faible":   { bg: "#E3E3FD", border: "#000091", text: "#000091" },
    "Low":      { bg: "#E3E3FD", border: "#000091", text: "#000091" },
    "Moyen":    { bg: "#FFF4F3", border: "#F95C5E", text: "#E1000F" },
    "Medium":   { bg: "#FFF4F3", border: "#F95C5E", text: "#E1000F" },
    "Élevé":    { bg: "#FEE9E5", border: "#E1000F", text: "#E1000F" },
    "High":     { bg: "#FEE9E5", border: "#E1000F", text: "#E1000F" },
    "Critique": { bg: "#E1000F", border: "#E1000F", text: "#FFFFFF" },
    "Critical": { bg: "#E1000F", border: "#E1000F", text: "#FFFFFF" },
  }[niveau] ?? { bg: "#F6F6F6", border: "#1E1E1E", text: "#1E1E1E" };

  const barColor = criticite >= 8 ? "#E1000F" : criticite >= 5 ? "#F95C5E" : "#000091";

  // 5. DICTIONNAIRE DE TRADUCTION DE L'HABILLAGE
  const lbl = isEn ? {
    subject: `[${niveau.toUpperCase()}] Security Advisory: ${titre}`,
    header: "Cyber Watch / Threat Intelligence",
    date: "Publication date",
    level: "LEVEL",
    crit: "GLOBAL CRITICALITY",
    summary: "Threat Summary",
    sector: "Targeted Sector",
    analysis: "Analysis Elements",
    attackers: "Modus Operandi / Attackers",
    victims: "Sectors / Targeted Victims",
    impact: "Technical & Operational Impact",
    indicators: "Indicators & Infrastructure Assets",
    mitre: "Identified MITRE ATT&CK techniques:",
    tools: "Associated tooling / malware:",
    techs: "Impacted systems & supply chain technologies:",
    reco: "Remediation Measures & Recommendations",
    cta: "Consult Full Report",
    footer1: "This is an automated security alert. Do not reply to this email.",
    footer2: "Unsubscribe from alerts"
  } : {
    subject: `[${niveau.toUpperCase()}] Bulletin d'alerte : ${titre}`,
    header: "Veille Cyber / Threat Intelligence",
    date: "Date de publication",
    level: "NIVEAU",
